type Server struct {
	Repo      *db.Repository
	TgManager *tg.Manager
}

func NewServer(repo *db.Repository, manager *tg.Manager) *Server {
	return &Server{
		Repo:      repo,
		TgManager: manager,
	}
}

func (s *Server) Router() http.Handler {
	r := chi.NewRouter()
	r.Use(middleware.Logger)
	r.Use(cors.Handler(cors.Options{
		AllowedOrigins:   []string{"http://localhost:5173", "http://127.0.0.1:5173"},
		AllowedMethods:   []string{"GET", "POST", "PUT", "DELETE", "OPTIONS"},
		AllowedHeaders:   []string{"Accept", "Authorization", "Content-Type", "X-CSRF-Token", "X-Session-ID"},
		ExposedHeaders:   []string{"Link"},
		AllowCredentials: true,
		MaxAge:           300,
	}))
	r.Use(auth.SessionIDMiddleware) // Global: all API requests must have X-Session-ID

	r.Get("/swagger/*", httpSwagger.WrapHandler)

	r.Route("/api", func(r chi.Router) {
		r.Route("/auth", func(r chi.Router) {
			r.Post("/send-code", s.SendCode)
			r.Post("/verify-code", s.VerifyCode)
			r.Post("/verify-password", s.VerifyPassword)
			r.Group(func(r chi.Router) {
				r.Use(auth.Middleware)
				r.Get("/me", s.GetMe)
				r.Post("/logout", s.Logout)
			})
		})

		r.Group(func(r chi.Router) {
			r.Use(auth.Middleware)
			r.Get("/channels", s.GetChannels)
			r.Get("/channels/{id}/messages", s.GetMessages)
			r.Post("/grab", s.GrabChannel)
			r.Get("/dialogs", s.GetDialogs)
			r.Post("/grab_by_id", s.GrabByID)
			r.Post("/grab_invite", s.GrabByInvite)
			r.Post("/search", s.SearchMessages)
			r.Post("/enrich", s.EnrichDialog)
			r.Get("/enrich/tasks", s.GetEnrichmentTasks)
		})
	})

	return r
}

type SearchRequest struct {
	Query string `json:"query"`
}

type SearchResponse struct {
	Analysis string       `json:"analysis"`
	Results  []db.Message `json:"results"`
}

type GrabRequest struct {
	Username string `json:"username"`
}

type GrabByIDRequest struct {
	ChatID int64 `json:"chat_id"`
}

type GrabByInviteRequest struct {
	Hash string `json:"hash"`
}

type EnrichRequest struct {
	DialogID int64 `json:"dialog_id"`
}

// GetChannels godoc
// @Summary List all grabbed channels
// @Description Get a list of all channels that have been grabbed
// @Tags channels
// @Produce json
// @Success 200 {array} db.Channel
// @Router /api/channels [get]
func (s *Server) GetChannels(w http.ResponseWriter, r *http.Request) {
	channels, err := s.Repo.GetChannels()
	if err != nil {
		http.Error(w, err.Error(), http.StatusInternalServerError)
		return
	}
	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(channels)
}

// GetMessages godoc
// @Summary List messages for a channel
// @Description Get a list of messages for a specific channel ID
// @Tags messages
// @Produce json
// @Param id path int true "Channel ID"
// @Success 200 {array} db.Message
// @Router /api/channels/{id}/messages [get]
func (s *Server) GetMessages(w http.ResponseWriter, r *http.Request) {
	idStr := chi.URLParam(r, "id")
	id, err := strconv.ParseInt(idStr, 10, 64)
	if err != nil {
		http.Error(w, "Invalid channel ID", http.StatusBadRequest)
		return
	}

	messages, err := s.Repo.GetMessages(id)
	if err != nil {
		http.Error(w, err.Error(), http.StatusInternalServerError)
		return
	}
	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(messages)
}

// GrabChannel godoc
// @Summary Grab a channel
// @Description Starts downloading channel history in the background
// @Tags channels
// @Accept json
// @Produce json
// @Param request body api.GrabRequest true "Channel Username"
// @Success 202 {string} string "Started grabbing in background"
// @Router /api/grab [post]
func (s *Server) GrabChannel(w http.ResponseWriter, r *http.Request) {
	var req GrabRequest
	if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
		http.Error(w, err.Error(), http.StatusBadRequest)
		return
	}

	if req.Username == "" {
		http.Error(w, "Username is required", http.StatusBadRequest)
		return
	}

	sessionID := auth.GetSessionID(r.Context())
	app, err := s.TgManager.GetApp(r.Context(), sessionID)
	if err != nil {
		http.Error(w, err.Error(), http.StatusInternalServerError)
		return
	}

	// Run in background...
	go func() {
		err := app.GrabChannel(context.Background(), req.Username)
		if err != nil {
			log.Printf("Background grab failed for session %s: %v", sessionID, err)
		}
	}()

	w.WriteHeader(http.StatusAccepted)
	w.Write([]byte("Started grabbing in background"))
}

// GetDialogs godoc
// @Summary List recent dialogs
// @Description Get a list of up to 100 recent dialogs to find Chat IDs
// @Tags dialogs
// @Produce json
// @Success 200 {array} object
// @Router /api/dialogs [get]
func (s *Server) GetDialogs(w http.ResponseWriter, r *http.Request) {
	app, err := s.TgManager.GetApp(r.Context(), auth.GetSessionID(r.Context()))
	if err != nil {
		http.Error(w, err.Error(), http.StatusInternalServerError)
		return
	}

	type DialogResponse struct {
		ID    int64  `json:"id"`
		Title string `json:"title"`
		Type  string `json:"type"`
	}

	chats, users, err := app.GetDialogs(r.Context())
	if err != nil {
		http.Error(w, err.Error(), http.StatusInternalServerError)
		return
	}

	var resp []DialogResponse
	for _, chatClass := range chats {
		switch c := chatClass.(type) {
		case *gotdtg.Chat:
			resp = append(resp, DialogResponse{ID: c.ID, Title: c.Title, Type: "group"})
		case *gotdtg.Channel:
			resp = append(resp, DialogResponse{ID: c.ID, Title: c.Title, Type: "supergroup/channel"})
		}
	}

	for _, userClass := range users {
		if u, ok := userClass.(*gotdtg.User); ok {
			// Don't skip deleted users, but label them
			if u.Deleted {
				resp = append(resp, DialogResponse{ID: u.ID, Title: "Deleted User", Type: "user"})
				continue
			}

			name := strings.TrimSpace(u.FirstName + " " + u.LastName)
			if name == "" {
				if u.Username != "" {
					name = "@" + u.Username
				} else {
					name = "User " + fmt.Sprint(u.ID)
				}
			}
			
			userType := "user"
			if u.Bot {
				userType = "bot"
			}
			
			resp = append(resp, DialogResponse{ID: u.ID, Title: name, Type: userType})
		}
	}

	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(resp)
}

